1	-------------------------------------------------------------------------------
2	-- Title      : SSI Protocol: https://confluence.slac.stanford.edu/x/0oyfD
3	-------------------------------------------------------------------------------
4	-- Company    : SLAC National Accelerator Laboratory
5	-------------------------------------------------------------------------------
6	-- Description:   This module generates
7	--                PseudoRandom Binary Sequence (PRBS) on Virtual Channel Lane.
8	-------------------------------------------------------------------------------
9	-- This file is part of 'SLAC Firmware Standard Library'.
10	-- It is subject to the license terms in the LICENSE.txt file found in the
11	-- top-level directory of this distribution and at:
12	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
13	-- No part of 'SLAC Firmware Standard Library', including this file,
14	-- may be copied, modified, propagated, or distributed except according to
15	-- the terms contained in the LICENSE.txt file.
16	-------------------------------------------------------------------------------
17	
18	library ieee;
19	use ieee.std_logic_1164.all;
20	use ieee.std_logic_unsigned.all;
21	use ieee.std_logic_arith.all;
22	
23	library surf;
24	use surf.StdRtlPkg.all;
25	use surf.AxiLitePkg.all;
26	use surf.AxiStreamPkg.all;
27	use surf.SsiPkg.all;
28	
29	entity SsiPrbsTx is
30	   generic (
31	      -- General Configurations
32	      TPD_G                      : time                    := 1 ns;
33	      RST_POLARITY_G             : sl                      := '1';  -- '1' for active HIGH reset, '0' for active LOW reset
34	      RST_ASYNC_G                : boolean                 := false;
35	      AXI_EN_G                   : sl                      := '1';
36	      AXI_DEFAULT_PKT_LEN_G      : slv(31 downto 0)        := x"00000FFF";
37	      AXI_DEFAULT_TRIG_DLY_G     : slv(31 downto 0)        := x"00000000";
38	      -- FIFO Configurations
39	      VALID_THOLD_G              : natural                 := 1;
40	      VALID_BURST_MODE_G         : boolean                 := false;
41	      SYNTH_MODE_G               : string                  := "inferred";
42	      MEMORY_TYPE_G              : string                  := "block";
43	      GEN_SYNC_FIFO_G            : boolean                 := false;
44	      CASCADE_SIZE_G             : positive                := 1;
45	      FIFO_ADDR_WIDTH_G          : positive                := 9;
46	      FIFO_PAUSE_THRESH_G        : positive                := 2**8;
47	      FIFO_INT_WIDTH_SELECT_G    : string                  := "WIDE";
48	      -- PRBS Configurations
49	      PRBS_SEED_SIZE_G           : natural range 32 to 512 := 32;
50	      PRBS_TAPS_G                : NaturalArray            := (0 => 31, 1 => 6, 2 => 2, 3 => 1);
51	      PRBS_INCREMENT_G           : boolean                 := false;  -- Increment mode by default instead of PRBS
52	      -- AXI Stream Configurations
53	      MASTER_AXI_STREAM_CONFIG_G : AxiStreamConfigType;
54	      MASTER_AXI_PIPE_STAGES_G   : natural range 0 to 16   := 0);
55	   port (
56	      -- Master Port (mAxisClk)
57	      mAxisClk        : in  sl;
58	      mAxisRst        : in  sl;
59	      mAxisMaster     : out AxiStreamMasterType;
60	      mAxisSlave      : in  AxiStreamSlaveType;
61	      -- Trigger Signal (locClk domain)
62	      locClk          : in  sl;
63	      locRst          : in  sl                     := not RST_POLARITY_G;
64	      trig            : in  sl                     := '1';
65	      trigAccept      : out sl;
66	      packetLength    : in  slv(31 downto 0)       := x"00000FFF";
67	      forceEofe       : in  sl                     := '0';
68	      busy            : out sl;
69	      tDest           : in  slv(7 downto 0)        := X"00";
70	      tId             : in  slv(7 downto 0)        := X"00";
71	      -- Optional: Axi-Lite Register Interface (locClk domain)
72	      axilReadMaster  : in  AxiLiteReadMasterType  := AXI_LITE_READ_MASTER_INIT_C;
73	      axilReadSlave   : out AxiLiteReadSlaveType;
74	      axilWriteMaster : in  AxiLiteWriteMasterType := AXI_LITE_WRITE_MASTER_INIT_C;
75	      axilWriteSlave  : out AxiLiteWriteSlaveType);
76	end SsiPrbsTx;
77	
78	architecture rtl of SsiPrbsTx is
79	
80	   constant EVENT_CNT_SIZE_C : integer := minimum(PRBS_SEED_SIZE_G, 32);
81	   constant PRBS_BYTES_C     : natural := wordCount(PRBS_SEED_SIZE_G, 8);
82	   constant PRBS_SSI_CONFIG_C : AxiStreamConfigType := (
83	      TSTRB_EN_C    => false,
84	      TDATA_BYTES_C => PRBS_BYTES_C,
85	      TDEST_BITS_C  => 8,
86	      TID_BITS_C    => 8,
87	      TKEEP_MODE_C  => MASTER_AXI_STREAM_CONFIG_G.TKEEP_MODE_C,
88	      TUSER_BITS_C  => 2,
89	      TUSER_MODE_C  => MASTER_AXI_STREAM_CONFIG_G.TUSER_MODE_C);
90	
91	   constant TRIG_SRC_AXI_C : sl := '0';
92	   constant TRIG_SRC_EXT_C : sl := '1';
93	
94	   type StateType is (
95	      IDLE_S,
96	      SEED_RAND_S,
97	      LENGTH_S,
98	      DATA_S);
99	
100	   type RegType is record
101	      cntRst         : sl;
102	      busy           : sl;
103	      overflow       : sl;
104	      frameCnt       : slv(31 downto 0);
105	      length         : slv(31 downto 0);
106	      packetLength   : slv(31 downto 0);
107	      dataCnt        : slv(31 downto 0);
108	      trigDly        : slv(31 downto 0);
109	      trigDlyCnt     : slv(31 downto 0);
110	      eventCnt       : slv(EVENT_CNT_SIZE_C-1 downto 0);
111	      randomData     : slv(PRBS_SEED_SIZE_G-1 downto 0);
112	      txAxisMaster   : AxiStreamMasterType;
113	      state          : StateType;
114	      axiEn          : sl;
115	      trigSrc        : sl;
116	      oneShot        : sl;
117	      trig           : sl;
118	      trigAccept     : sl;
119	      trigger        : sl;
120	      cntData        : sl;
121	      tDest          : slv(7 downto 0);
122	      tId            : slv(7 downto 0);
123	      axilReadSlave  : AxiLiteReadSlaveType;
124	      axilWriteSlave : AxiLiteWriteSlaveType;
125	   end record;
126	
127	   constant REG_INIT_C : RegType := (
128	      cntRst         => '1',
129	      busy           => '1',
130	      overflow       => '0',
131	      frameCnt       => (others => '0'),
132	      length         => (others => '0'),
133	      packetLength   => AXI_DEFAULT_PKT_LEN_G,
134	      dataCnt        => (others => '0'),
135	      trigDly        => AXI_DEFAULT_TRIG_DLY_G,
136	      trigDlyCnt     => (others => '0'),
137	      eventCnt       => toSlv(1, EVENT_CNT_SIZE_C),
138	      randomData     => (others => '0'),
139	      txAxisMaster   => axiStreamMasterInit(PRBS_SSI_CONFIG_C),
140	      state          => IDLE_S,
141	      axiEn          => AXI_EN_G,
142	      trigSrc        => ite(AXI_EN_G = '1', TRIG_SRC_AXI_C, TRIG_SRC_EXT_C),
143	      oneShot        => '0',
144	      trig           => '0',
145	      trigAccept     => '0',
146	      trigger        => '0',
147	      cntData        => toSl(PRBS_INCREMENT_G),
148	      tDest          => X"00",
149	      tId            => X"00",
150	      axilReadSlave  => AXI_LITE_READ_SLAVE_INIT_C,
151	      axilWriteSlave => AXI_LITE_WRITE_SLAVE_INIT_C);
152	
153	   signal r   : RegType := REG_INIT_C;
154	   signal rin : RegType;
155	
156	   signal txSlave : AxiStreamSlaveType;
157	   signal txCtrl  : AxiStreamCtrlType;
158	
159	begin
160	
161	   assert ((PRBS_SEED_SIZE_G = 32) or (PRBS_SEED_SIZE_G = 64) or (PRBS_SEED_SIZE_G = 128) or (PRBS_SEED_SIZE_G = 256) or (PRBS_SEED_SIZE_G = 512)) report "PRBS_SEED_SIZE_G must be either [32,64,128,256,512]" severity failure;
162	
163	   comb : process (axilReadMaster, axilWriteMaster, forceEofe, locRst,
164	                   packetLength, r, tDest, tId, trig, txCtrl, txSlave) is
165	      variable v      : RegType;
166	      variable axilEp : AxiLiteEndpointType;
167	   begin
168	      -- Latch the current value
169	      v := r;
170	
171	      -- Reset strobes
172	      v.cntRst := '0';
173	
174	      ----------------------------------------------------------------------------------------------
175	      -- Axi-Lite Registers
176	      ----------------------------------------------------------------------------------------------
177	      axiSlaveWaitTxn(axilEp, axilWriteMaster, axilReadMaster, v.axilWriteSlave, v.axilReadSlave);
178	
179	      axiSlaveRegister(axilEp, X"00", 0, v.axiEn);
180	      axiSlaveRegister(axilEp, X"00", 1, v.trig);
181	      axiSlaveRegisterR(axilEp, X"00", 2, r.busy);
182	      axiSlaveRegisterR(axilEp, X"00", 3, r.overflow);
183	      axiSlaveRegister(axilEp, X"00", 5, v.cntData);
184	      axiSlaveRegister(axilEp, X"00", 6, v.trigSrc);
185	
186	      axiSlaveRegister(axilEp, X"04", 0, v.packetLength);
187	      axiSlaveRegister(axilEp, X"08", 0, v.tDest);
188	      axiSlaveRegister(axilEp, X"08", 8, v.tId);
189	      axiSlaveRegister(axilEp, X"0C", 0, v.dataCnt);
190	      axiSlaveRegister(axilEp, X"18", 0, v.oneShot);
191	      axiSlaveRegister(axilEp, X"1C", 0, v.trigDly);
192	
193	      axiSlaveRegisterR(axilEp, X"10", 0, r.eventCnt);
194	      axiSlaveRegisterR(axilEp, X"14", 0, r.randomData(minimum(PRBS_SEED_SIZE_G-1, 31) downto 0));
195	      axiSlaveRegisterR(axilEp, X"1C", 0, r.trigDly);
196	
197	      axiSlaveRegisterR(axilEp, X"20", 0, toSlv(PRBS_SEED_SIZE_G, 32));
198	      axiSlaveRegisterR(axilEp, X"24", 0, r.frameCnt);
199	
200	      axiWrDetect(axilEp, X"FC", v.cntRst);
201	
202	      axiSlaveDefault(axilEp, v.axilWriteSlave, v.axilReadSlave, AXI_RESP_DECERR_C);
203	
204	      ----------------------------------------------------------------------------------------------
205	      -- PRBS Stream Logic
206	      ----------------------------------------------------------------------------------------------
207	
208	      -- Check for delay between AXI triggers
209	      if (r.trigDlyCnt = r.trigDly) or (r.trigDly /= v.trigDly) then
210	         v.trigDlyCnt := (others => '0');
211	         v.trigger    := r.trig;
212	      elsif (r.trigger = '0') then
213	         v.trigDlyCnt := r.trigDlyCnt + 1;
214	      end if;
215	
216	      -- Override axi settings if axi not enabled
217	      if (v.axiEn = '0') then
218	         v.trigger      := trig;
219	         v.packetLength := packetLength;
220	         v.tDest        := tDest;
221	         v.tId          := tId;
222	      end if;
223	
224	      -- Special mode with axi settings and external triggers
225	      if (r.axiEn = '1' and r.trigSrc = TRIG_SRC_EXT_C) then
226	         v.trigger := trig;
227	      end if;
228	
229	      -- trigAccept is pulsed each time trigger is seen to start a new frame
230	      v.trigAccept := '0';
231	
232	      -- Check for overflow condition or forced EOFE
233	      if (txCtrl.overflow = '1') or (forceEofe = '1') then
234	         -- Latch the overflow error bit for the data packet
235	         v.overflow := '1';
236	      end if;
237	
238	      -- Check the AXIS flow control
239	      if txSlave.tReady = '1' then
240	         v.txAxisMaster.tValid := '0';
241	         v.txAxisMaster.tLast  := '0';
242	         v.txAxisMaster.tUser  := (others => '0');
243	      end if;
244	
245	      -- State Machine
246	      case (r.state) is
247	         ----------------------------------------------------------------------
248	         when IDLE_S =>
249	            -- Reset the busy flag
250	            v.busy := '0';
251	            -- Check for a trigger
252	            if (r.trigger = '1') or (r.oneShot = '1') then
253	               -- Reset the one shot
254	               v.oneShot                                 := '0';
255	               v.trigger                                 := '0';
256	               v.trigAccept                              := '1';
257	               -- Latch the generator seed
258	               v.randomData                              := (others => '0');
259	               v.randomData(EVENT_CNT_SIZE_C-1 downto 0) := r.eventCnt;
260	               -- Set the busy flag
261	               v.busy                                    := '1';
262	               -- Reset the overflow flag
263	               v.overflow                                := '0';
264	               -- Latch the configuration
265	               v.txAxisMaster.tDest                      := r.tDest;
266	               v.txAxisMaster.tId                        := r.tId;
267	               -- Check the packet length request value
268	               if r.packetLength = 0 then
269	                  -- Force minimum packet length of 2 (+1)
270	                  v.length := toSlv(2, 32);
271	               elsif r.packetLength = 1 then
272	                  -- Force minimum packet length of 2 (+1)
273	                  v.length := toSlv(2, 32);
274	               else
275	                  v.length := r.packetLength;
276	               end if;
277	               -- Next State
278	               v.state := SEED_RAND_S;
279	            end if;
280	         ----------------------------------------------------------------------
281	         when SEED_RAND_S =>
282	            -- Check if the FIFO is ready
283	            if v.txAxisMaster.tvalid = '0' then
284	               -- Send the random seed word
285	               v.txAxisMaster.tvalid                             := '1';
286	               v.txAxisMaster.tData(PRBS_SEED_SIZE_G-1 downto 0) := (others => '0');
287	               v.txAxisMaster.tData(EVENT_CNT_SIZE_C-1 downto 0) := r.eventCnt;
288	               -- Generate the next random data word
289	--               for i in 0 to PRBS_SEED_SIZE_G-1 loop
290	               v.randomData                                      := lfsrShift(v.randomData, PRBS_TAPS_G, '0');
291	--               end loop;
292	               -- Increment the counter
293	               v.eventCnt                                        := r.eventCnt + 1;
294	               -- Increment the counter
295	               v.dataCnt                                         := r.dataCnt + 1;
296	               -- Set the SOF bit
297	               ssiSetUserSof(PRBS_SSI_CONFIG_C, v.txAxisMaster, '1');
298	               -- Count the frame
299	               v.frameCnt                                        := r.frameCnt + 1;
300	               -- Next State
301	               v.state                                           := LENGTH_S;
302	            end if;
303	         ----------------------------------------------------------------------
304	         when LENGTH_S =>
305	            -- Check if the FIFO is ready
306	            if v.txAxisMaster.tvalid = '0' then
307	               -- Send the upper packetLength value
308	               v.txAxisMaster.tvalid             := '1';
309	               v.txAxisMaster.tData              := (others => '0');
310	               v.txAxisMaster.tData(31 downto 0) := r.length;
311	               -- Increment the counter
312	               v.dataCnt                         := r.dataCnt + 1;
313	               -- Next State
314	               v.state                           := DATA_S;
315	            end if;
316	         ----------------------------------------------------------------------
317	         when DATA_S =>
318	            -- Check if the FIFO is ready
319	            if v.txAxisMaster.tvalid = '0' then
320	               -- Send the random data word
321	               v.txAxisMaster.tValid := '1';
322	               -- Check if we are sending PRBS or counter data
323	               if r.cntData = '0' then
324	                  -- PRBS data
325	                  v.txAxisMaster.tData(PRBS_SEED_SIZE_G-1 downto 0) := r.randomData;
326	               else
327	                  -- Counter data
328	                  v.txAxisMaster.tData(PRBS_SEED_SIZE_G-1 downto 0) := (others => '0');
329	                  v.txAxisMaster.tData(31 downto 0)                 := r.dataCnt;
330	               end if;
331	               -- Generate the next random data word
332	--               for i in 0 to PRBS_SEED_SIZE_G-1 loop
333	               v.randomData := lfsrShift(v.randomData, PRBS_TAPS_G, '0');
334	--               end loop;
335	               -- Increment the counter
336	               v.dataCnt    := r.dataCnt + 1;
337	               -- Check the counter
338	               if r.dataCnt = r.length then
339	                  -- Reset the counter
340	                  v.dataCnt            := (others => '0');
341	                  -- Set the EOF bit
342	                  v.txAxisMaster.tLast := '1';
343	                  -- Set the EOFE bit
344	                  ssiSetUserEofe(PRBS_SSI_CONFIG_C, v.txAxisMaster, r.overflow);
345	                  -- Reset the busy flag
346	                  v.busy               := '0';
347	                  -- Next State
348	                  v.state              := IDLE_S;
349	               end if;
350	            end if;
351	      ----------------------------------------------------------------------
352	      end case;
353	
354	      -- Check for counter reset
355	      if (r.cntRst = '1') then
356	         v.frameCnt := (others => '0');
357	      end if;
358	
359	      -- Reset
360	      if (RST_ASYNC_G = false and locRst = RST_POLARITY_G) then
361	         v := REG_INIT_C;
362	      end if;
363	
364	      -- Register the variable for next clock cycle
365	      rin <= v;
366	
367	      -- Outputs
368	      busy           <= r.busy;
369	      trigAccept     <= r.trigAccept;
370	      axilReadSlave  <= r.axilReadSlave;
371	      axilWriteSlave <= r.axilWriteSlave;
372	
373	   end process comb;
374	
375	   seq : process (locClk, locRst) is
376	   begin
377	      if (RST_ASYNC_G) and (locRst = RST_POLARITY_G) then
378	         r <= REG_INIT_C after TPD_G;
379	      elsif rising_edge(locClk) then
380	         r <= rin after TPD_G;
381	      end if;
382	   end process seq;
383	
384	   AxiStreamFifo_Inst : entity surf.AxiStreamFifoV2
385	      generic map(
386	         -- General Configurations
387	         TPD_G               => TPD_G,
388	         RST_POLARITY_G      => RST_POLARITY_G,
389	         RST_ASYNC_G         => RST_ASYNC_G,
390	         INT_PIPE_STAGES_G   => MASTER_AXI_PIPE_STAGES_G,
391	         PIPE_STAGES_G       => MASTER_AXI_PIPE_STAGES_G,
392	         SLAVE_READY_EN_G    => true,
393	         VALID_THOLD_G       => VALID_THOLD_G,
394	         VALID_BURST_MODE_G  => VALID_BURST_MODE_G,
395	         -- FIFO configurations
396	         SYNTH_MODE_G        => SYNTH_MODE_G,
397	         MEMORY_TYPE_G       => MEMORY_TYPE_G,
398	         GEN_SYNC_FIFO_G     => GEN_SYNC_FIFO_G,
399	         CASCADE_SIZE_G      => CASCADE_SIZE_G,
400	         FIFO_ADDR_WIDTH_G   => FIFO_ADDR_WIDTH_G,
401	         FIFO_FIXED_THRESH_G => true,
402	         FIFO_PAUSE_THRESH_G => FIFO_PAUSE_THRESH_G,
403	         CASCADE_PAUSE_SEL_G => (CASCADE_SIZE_G-1),
404	         INT_WIDTH_SELECT_G  => FIFO_INT_WIDTH_SELECT_G,
405	         -- AXI Stream Port Configurations
406	         SLAVE_AXI_CONFIG_G  => PRBS_SSI_CONFIG_C,
407	         MASTER_AXI_CONFIG_G => MASTER_AXI_STREAM_CONFIG_G)
408	      port map (
409	         -- Slave Port
410	         sAxisClk    => locClk,
411	         sAxisRst    => locRst,
412	         sAxisMaster => r.txAxisMaster,
413	         sAxisSlave  => txSlave,
414	         sAxisCtrl   => txCtrl,
415	         -- Master Port
416	         mAxisClk    => mAxisClk,
417	         mAxisRst    => mAxisRst,
418	         mAxisMaster => mAxisMaster,
419	         mAxisSlave  => mAxisSlave);
420	
421	end rtl;
422

