1	-------------------------------------------------------------------------------
2	-- Title      : SSI Protocol: https://confluence.slac.stanford.edu/x/0oyfD
3	-------------------------------------------------------------------------------
4	-- Company    : SLAC National Accelerator Laboratory
5	-------------------------------------------------------------------------------
6	-- Description: Inbound AXI Stream FIFO SSI Filter ....
7	--              Tags frames with EOFE on double SOFs
8	--              Drops frames that are missing SOF frame marker
9	--              Tags frames with EOFE on change in TDEST during move
10	--              Generates the overflow FIFO signal for user logic
11	-------------------------------------------------------------------------------
12	-- This file is part of 'SLAC Firmware Standard Library'.
13	-- It is subject to the license terms in the LICENSE.txt file found in the
14	-- top-level directory of this distribution and at:
15	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
16	-- No part of 'SLAC Firmware Standard Library', including this file,
17	-- may be copied, modified, propagated, or distributed except according to
18	-- the terms contained in the LICENSE.txt file.
19	-------------------------------------------------------------------------------
20	
21	library ieee;
22	use ieee.std_logic_1164.all;
23	use ieee.std_logic_arith.all;
24	use ieee.std_logic_unsigned.all;
25	
26	library surf;
27	use surf.StdRtlPkg.all;
28	use surf.AxiStreamPkg.all;
29	use surf.SsiPkg.all;
30	
31	entity SsiIbFrameFilter is
32	   generic (
33	      TPD_G            : time    := 1 ns;
34	      RST_POLARITY_G   : sl      := '1';  -- '1' for active HIGH reset, '0' for active LOW reset
35	      RST_ASYNC_G      : boolean := false;
36	      SLAVE_READY_EN_G : boolean := true;
37	      AXIS_CONFIG_G    : AxiStreamConfigType);
38	   port (
39	      -- Slave Interface (User Application Interface)
40	      sAxisMaster    : in  AxiStreamMasterType;
41	      sAxisSlave     : out AxiStreamSlaveType;
42	      sAxisCtrl      : out AxiStreamCtrlType;
43	      sAxisDropWord  : out sl;          -- Word dropped status output
44	      sAxisDropFrame : out sl;          -- Frame dropped status output
45	      -- Master Interface (AXIS FIFO Write Interface)
46	      mAxisMaster    : out AxiStreamMasterType;
47	      mAxisSlave     : in  AxiStreamSlaveType;
48	      mAxisCtrl      : in  AxiStreamCtrlType;
49	      -- Clock and Reset
50	      axisClk        : in  sl;
51	      axisRst        : in  sl);
52	end SsiIbFrameFilter;
53	
54	architecture rtl of SsiIbFrameFilter is
55	
56	   constant SLAVE_INIT_C : AxiStreamSlaveType := ite(SLAVE_READY_EN_G, AXI_STREAM_SLAVE_INIT_C, AXI_STREAM_SLAVE_FORCE_C);
57	
58	   constant CHECK_TDEST_C : boolean := AXIS_CONFIG_G.TDEST_BITS_C > 0;
59	   constant TDEST_BITS_C  : natural := ite(CHECK_TDEST_C, AXIS_CONFIG_G.TDEST_BITS_C, 1);
60	
61	   type StateType is (
62	      IDLE_S,
63	      BLOWOFF_S,
64	      MOVE_S,
65	      INSERT_EOFE_S);
66	
67	   type RegType is record
68	      overflow     : sl;
69	      wordDropped  : sl;
70	      frameDropped : sl;
71	      tDest        : slv(TDEST_BITS_C-1 downto 0);
72	      master       : AxiStreamMasterType;
73	      slave        : AxiStreamSlaveType;
74	      state        : StateType;
75	   end record RegType;
76	
77	   constant REG_INIT_C : RegType := (
78	      overflow     => '0',
79	      wordDropped  => '0',
80	      frameDropped => '0',
81	      tDest        => (others => '0'),
82	      master       => AXI_STREAM_MASTER_INIT_C,
83	      slave        => SLAVE_INIT_C,
84	      state        => IDLE_S);
85	
86	   signal r   : RegType := REG_INIT_C;
87	   signal rin : RegType;
88	
89	begin
90	
91	--   assert (AXIS_CONFIG_G.TDEST_INTERLEAVE_C = false)
92	--      report "SsiIbFrameFilter does NOT support interleaved TDEST" severity failure;
93	
94	   assert (AXIS_CONFIG_G.TUSER_BITS_C >= 2)
95	      report "SsiIbFrameFilter:  AXIS_CONFIG_G.TUSER_BITS_C must be >= 2" severity failure;
96	
97	   comb : process (axisRst, mAxisCtrl, mAxisSlave, r, sAxisMaster) is
98	      variable v   : RegType;
99	      variable sof : sl;
100	   begin
101	      -- Latch the current value
102	      v := r;
103	
104	      -- Reset strobe Signals
105	      v.overflow     := '0';
106	      v.wordDropped  := '0';
107	      v.frameDropped := '0';
108	
109	      -- Flow Control Signals
110	      v.slave := SLAVE_INIT_C;
111	      if (mAxisSlave.tReady = '1') then
112	         v.master.tValid := '0';
113	      end if;
114	
115	      -- Get the SOF status
116	      sof := ssiGetUserSof(AXIS_CONFIG_G, sAxisMaster);
117	
118	      -- State Machine
119	      case (r.state) is
120	         ----------------------------------------------------------------------
121	         when IDLE_S =>
122	            -- Check for new inbound data
123	            if (sAxisMaster.tValid = '1') then
124	
125	               -- Check for overflow
126	               if (v.master.tValid = '1') and not(SLAVE_READY_EN_G) then
127	
128	                  -- Accept the data
129	                  v.slave.tReady := '1';
130	
131	                  -- Set the flag
132	                  v.overflow := '1';
133	
134	                  -- Strobe the error flags
135	                  v.wordDropped  := sAxisMaster.tValid;
136	                  v.frameDropped := sAxisMaster.tLast;
137	
138	               -- Else ready to accept new data
139	               elsif (v.master.tValid = '0') then
140	
141	                  -- Accept the data
142	                  v.slave.tReady := '1';
143	
144	                  -- Check for SOF
145	                  if (sof = '1') then
146	
147	                     -- Move the data bus
148	                     v.master := sAxisMaster;
149	
150	                     -- Latch tDest
151	                     v.tDest := sAxisMaster.tDest(TDEST_BITS_C-1 downto 0);
152	
153	                     -- Check for no EOF
154	                     if (sAxisMaster.tLast = '0') then
155	                        -- Next state
156	                        v.state := MOVE_S;
157	                     end if;
158	
159	                  -- No SOF frame maker detected
160	                  else
161	
162	                     -- Strobe the error flags
163	                     v.wordDropped  := sAxisMaster.tValid;
164	                     v.frameDropped := sAxisMaster.tLast;
165	
166	                     -- Check for non-EOF
167	                     if (sAxisMaster.tLast = '0') then
168	                        -- Next state
169	                        v.state := BLOWOFF_S;
170	                     end if;
171	
172	                  end if;
173	
174	               end if;
175	            end if;
176	         ----------------------------------------------------------------------
177	         when BLOWOFF_S =>
178	            -- Blow-off the data
179	            v.slave.tReady := '1';
180	
181	            -- Strobe the error flags
182	            v.wordDropped  := sAxisMaster.tValid;
183	            v.frameDropped := sAxisMaster.tLast;
184	
185	            -- Check for EOF
186	            if (sAxisMaster.tValid = '1') and (sAxisMaster.tLast = '1') then
187	               -- Next state
188	               v.state := IDLE_S;
189	            end if;
190	         ----------------------------------------------------------------------
191	         when MOVE_S =>
192	            -- Check for new inbound data
193	            if (sAxisMaster.tValid = '1') then
194	
195	               -- Check for overflow
196	               if (v.master.tValid = '1') and not(SLAVE_READY_EN_G) then
197	
198	                  -- Accept the data
199	                  v.slave.tReady := '1';
200	
201	                  -- Set the flag
202	                  v.overflow := '1';
203	
204	                  -- Strobe the error flags
205	                  v.wordDropped  := sAxisMaster.tValid;
206	                  v.frameDropped := sAxisMaster.tLast;
207	
208	                  -- Next state
209	                  v.state := INSERT_EOFE_S;
210	
211	               -- Else ready to accept new data
212	               elsif (v.master.tValid = '0') then
213	
214	                  -- Accept the data
215	                  v.slave.tReady := '1';
216	
217	                  -- Move the data bus
218	                  v.master := sAxisMaster;
219	
220	                  -- Check for EOF
221	                  if (sAxisMaster.tLast = '1') then
222	                     -- Next state
223	                     v.state := IDLE_S;
224	                  end if;
225	
226	                  -- Check for SSI framing errors (repeated SOF or interleaved frame)
227	                  if (sof = '1') or (CHECK_TDEST_C and (r.tDest /= sAxisMaster.tDest(TDEST_BITS_C-1 downto 0))) then
228	
229	                     -- Set the EOF flag
230	                     v.master.tLast := '1';
231	
232	                     -- Set the EOFE flag
233	                     ssiSetUserEofe(AXIS_CONFIG_G, v.master, '1');
234	
235	                     -- Override SOF flag
236	                     ssiSetUserSof(AXIS_CONFIG_G, v.master, '0');
237	
238	                     -- Strobe the error flags
239	                     v.wordDropped  := sAxisMaster.tValid;
240	                     v.frameDropped := sAxisMaster.tLast;
241	
242	                     -- Check for non-EOF
243	                     if (sAxisMaster.tLast = '0') then
244	                        -- Next state
245	                        v.state := BLOWOFF_S;
246	                     end if;
247	
248	                  end if;
249	               end if;
250	            end if;
251	         ----------------------------------------------------------------------
252	         when INSERT_EOFE_S =>
253	            -- Blow-off the data
254	            v.slave.tReady := '1';
255	
256	            -- Set the flag
257	            v.overflow := sAxisMaster.tValid;
258	
259	            -- Strobe the error flags
260	            v.wordDropped  := sAxisMaster.tValid;
261	            v.frameDropped := sAxisMaster.tLast;
262	
263	            -- Check if AXI stream FIFO can be written into
264	            if (v.master.tValid = '0') then
265	
266	               -- Write to FIFO
267	               v.master.tValid := '1';
268	
269	               -- Set the EOF flag
270	               v.master.tLast := '1';
271	
272	               -- Set the EOFE flag
273	               ssiSetUserEofe(AXIS_CONFIG_G, v.master, '1');
274	
275	               -- Override SOF flag
276	               ssiSetUserSof(AXIS_CONFIG_G, v.master, '0');
277	
278	               -- Next state
279	               v.state := IDLE_S;
280	
281	            end if;
282	      ----------------------------------------------------------------------
283	      end case;
284	
285	      -- Slave Outputs
286	      sAxisSlave         <= v.slave;
287	      sAxisCtrl          <= mAxisCtrl;
288	      sAxisCtrl.overflow <= r.overflow or mAxisCtrl.overflow;
289	      sAxisDropWord      <= r.wordDropped;
290	      sAxisDropFrame     <= r.frameDropped;
291	
292	      -- Master Outputs
293	      mAxisMaster <= r.master;
294	
295	      -- Synchronous Reset
296	      if (RST_ASYNC_G = false and axisRst = RST_POLARITY_G) then
297	         v := REG_INIT_C;
298	      end if;
299	
300	      -- Register the variable for next clock cycle
