30	      RST_POLARITY_G      : sl       := '1';  -- '1' for active HIGH reset, '0' for active LOW reset
31	      RST_ASYNC_G         : boolean  := false;
32	      EN_TIMEOUT_G        : boolean  := true;
33	      MAXIS_CLK_FREQ_G    : real     := 156.25E+06;  -- In units of Hz
34	      TIMEOUT_G           : real     := 1.0E-3;      -- In units of seconds
35	      FRAME_LIMIT_G       : positive := 1024;  -- In units of MASTER_AXI_CONFIG_G.TDATA_BYTES_C
36	      COMMON_CLK_G        : boolean  := false;  -- True if sAxisClk and mAxisClk are the same clock
37	      SLAVE_FIFO_G        : boolean  := false;
38	      MASTER_FIFO_G       : boolean  := false;
39	      SLAVE_READY_EN_G    : boolean  := true;
40	      SLAVE_AXI_CONFIG_G  : AxiStreamConfigType;
41	      MASTER_AXI_CONFIG_G : AxiStreamConfigType);
42	   port (
43	      -- Slave Port
44	      sAxisClk    : in  sl;
45	      sAxisRst    : in  sl;
46	      sAxisMaster : in  AxiStreamMasterType;
47	      sAxisSlave  : out AxiStreamSlaveType;
48	      -- Master Port
49	      mAxisClk    : in  sl;
50	      mAxisRst    : in  sl;
51	      mAxisMaster : out AxiStreamMasterType;
52	      mAxisSlave  : in  AxiStreamSlaveType);
53	end SsiFrameLimiter;
54	
55	architecture rtl of SsiFrameLimiter is
56	
57	   constant TIMEOUT_C : natural := getTimeRatio(MAXIS_CLK_FREQ_G * TIMEOUT_G, 1.0);
58	
59	   constant SLAVE_FIFO_C : boolean := ite (SLAVE_FIFO_G or (COMMON_CLK_G = false) or (SLAVE_READY_EN_G = false), true, false);
60	
61	   type StateType is (
62	      IDLE_S,
63	      MOVE_S);
64	
65	   type RegType is record
66	      cnt      : natural range 0 to FRAME_LIMIT_G-1;
67	      timer    : natural range 0 to TIMEOUT_C-1;
68	      rxSlave  : AxiStreamSlaveType;
69	      txMaster : AxiStreamMasterType;
70	      state    : StateType;
71	   end record RegType;
72	   constant REG_INIT_C : RegType := (
73	      cnt      => 0,
74	      timer    => 0,
75	      rxSlave  => AXI_STREAM_SLAVE_INIT_C,
76	      txMaster => AXI_STREAM_MASTER_INIT_C,
77	      state    => IDLE_S);
78	
79	   signal r   : RegType := REG_INIT_C;
80	   signal rin : RegType;
81	
82	   signal rxMaster : AxiStreamMasterType;
83	   signal rxSlave  : AxiStreamSlaveType;
84	   signal txMaster : AxiStreamMasterType;
85	   signal txSlave  : AxiStreamSlaveType;
86	
87	begin
88	
89	   BYPASS_FIFO_RX : if (SLAVE_FIFO_C = false) generate
90	      U_Resize_OB : entity surf.AxiStreamGearbox
91	         generic map (
92	            -- General Configurations
93	            TPD_G               => TPD_G,
94	            RST_POLARITY_G      => RST_POLARITY_G,
95	            RST_ASYNC_G         => RST_ASYNC_G,
96	            READY_EN_G          => true,
97	            -- AXI Stream Port Configurations
98	            SLAVE_AXI_CONFIG_G  => SLAVE_AXI_CONFIG_G,
99	            MASTER_AXI_CONFIG_G => MASTER_AXI_CONFIG_G)
100	         port map (
101	            -- Clock and reset
102	            axisClk     => mAxisClk,
103	            axisRst     => mAxisRst,
104	            -- Slave Port
105	            sAxisMaster => sAxisMaster,
106	            sAxisSlave  => sAxisSlave,
107	            -- Master Port
108	            mAxisMaster => rxMaster,
109	            mAxisSlave  => rxSlave);
110	   end generate;
111	
112	   GEN_FIFO_RX : if (SLAVE_FIFO_C = true) generate
113	      FIFO_RX : entity surf.AxiStreamFifoV2
114	         generic map (
115	            -- General Configurations
116	            TPD_G               => TPD_G,
117	            RST_POLARITY_G      => RST_POLARITY_G,
118	            RST_ASYNC_G         => RST_ASYNC_G,
119	            PIPE_STAGES_G       => 0,
120	            SLAVE_READY_EN_G    => SLAVE_READY_EN_G,
121	            VALID_THOLD_G       => 1,
122	            -- FIFO configurations
123	            MEMORY_TYPE_G       => "distributed",
124	            GEN_SYNC_FIFO_G     => COMMON_CLK_G,
125	            FIFO_ADDR_WIDTH_G   => 4,
126	            -- AXI Stream Port Configurations
127	            SLAVE_AXI_CONFIG_G  => SLAVE_AXI_CONFIG_G,
128	            MASTER_AXI_CONFIG_G => MASTER_AXI_CONFIG_G)
129	         port map (
130	            -- Slave Port
131	            sAxisClk    => sAxisClk,
132	            sAxisRst    => sAxisRst,
133	            sAxisMaster => sAxisMaster,
134	            sAxisSlave  => sAxisSlave,
135	            -- Master Port
136	            mAxisClk    => mAxisClk,
137	            mAxisRst    => mAxisRst,
138	            mAxisMaster => rxMaster,
139	            mAxisSlave  => rxSlave);
140	   end generate;
141	
142	   comb : process (mAxisRst, r, rxMaster, txSlave) is
143	      variable v      : RegType;
144	      variable i      : natural;
145	      variable sofDet : sl;
146	   begin
147	      -- Latch the current value
148	      v := r;
149	
150	      -- Check for SOF
151	      sofDet := ssiGetUserSof(MASTER_AXI_CONFIG_G, rxMaster);
152	
153	      -- Reset the flags
154	      v.rxSlave := AXI_STREAM_SLAVE_INIT_C;
155	      if (txSlave.tReady = '1') then
156	         v.txMaster.tValid := '0';
157	      end if;
158	
159	      -- State Machine
160	      case r.state is
161	         ----------------------------------------------------------------------
162	         when IDLE_S =>
163	            -- Preset the counter
164	            v.cnt := 1;
165	            -- Check if ready to move data
166	            if (v.txMaster.tValid = '0') and (rxMaster.tValid = '1') then
167	               -- Accept the data
168	               v.rxSlave.tReady := '1';
169	               -- Check for SOF
170	               if sofDet = '1' then
171	                  -- Move the data
172	                  v.txMaster := rxMaster;
173	                  -- Check for non-EOF
174	                  if rxMaster.tLast = '0' then
175	                     -- Next state
176	                     v.state := MOVE_S;
177	                  end if;
178	               end if;
179	            end if;
180	         ----------------------------------------------------------------------
181	         when MOVE_S =>
182	            -- Check if ready to move data
183	            if (v.txMaster.tValid = '0') and (rxMaster.tValid = '1') then
184	               -- Accept the data
185	               v.rxSlave.tReady := '1';
186	               -- Move the data
187	               v.txMaster       := rxMaster;
188	               -- Check for double SOF
189	               if sofDet = '1' then
190	                  -- Set EOF and EOFE
191	                  v.txMaster.tLast := '1';
192	                  ssiSetUserEofe(MASTER_AXI_CONFIG_G, v.txMaster, '1');
193	                  -- Next state
194	                  v.state          := IDLE_S;
195	               -- Check for EOF
196	               elsif rxMaster.tLast = '1' then
197	                  -- Next state
198	                  v.state := IDLE_S;
199	               -- Check if reach limiter value
200	               elsif r.cnt = (FRAME_LIMIT_G-1) then
201	                  -- Set EOF and EOFE
202	                  v.txMaster.tLast := '1';
203	                  ssiSetUserEofe(MASTER_AXI_CONFIG_G, v.txMaster, '1');
204	                  -- Next state
205	                  v.state          := IDLE_S;
206	               else
207	                  -- Increment the counter
208	                  v.cnt := r.cnt + 1;
209	               end if;
210	            end if;
211	      ----------------------------------------------------------------------
212	      end case;
213	
214	      -- Check if timeout is enabled
215	      if EN_TIMEOUT_G then
216	         -- Check if in (or going into) IDLE state
217	         if (r.state = IDLE_S) or (v.state = IDLE_S) then
218	            -- Reset the timer
219	            v.timer := 0;
220	         else
221	            -- Check the timer
222	            if (r.timer /= (TIMEOUT_C-1)) then
223	               -- Increment the timer
224	               v.timer := r.timer + 1;
225	            else
226	               -- Check ready to move data
227	               if (v.txMaster.tValid = '0') then
228	                  -- Set EOF and EOFE
229	                  v.txMaster.tValid := '1';
230	                  v.txMaster.tLast  := '1';
231	                  ssiSetUserEofe(MASTER_AXI_CONFIG_G, v.txMaster, '1');
232	                  -- Next state
233	                  v.state           := IDLE_S;
234	               end if;
235	            end if;
236	         end if;
237	      end if;
238	
239	      -- Combinatorial outputs before the reset
240	      rxSlave <= v.rxSlave;
241	
242	      -- Reset
243	      if (RST_ASYNC_G = false and mAxisRst = RST_POLARITY_G) then
244	         v := REG_INIT_C;
245	      end if;
246	
247	      -- Register the variable for next clock cycle
248	      rin <= v;
249	
250	      -- Registered Outputs
251	      txMaster <= r.txMaster;
252	
253	   end process comb;
254	
255	   seq : process (mAxisClk, mAxisRst) is
256	   begin
257	      if (RST_ASYNC_G) and (mAxisRst = RST_POLARITY_G) then
258	         r <= REG_INIT_C after TPD_G;
259	      elsif rising_edge(mAxisClk) then
260	         r <= rin after TPD_G;
261	      end if;
262	   end process seq;
263	
264	   BYPASS_FIFO_TX : if (MASTER_FIFO_G = false) generate
265	      mAxisMaster <= txMaster;
266	      txSlave     <= mAxisSlave;
267	   end generate;
268	
269	   GEN_FIFO_TX : if (MASTER_FIFO_G = true) generate
270	      FIFO_TX : entity surf.AxiStreamFifoV2
271	         generic map (
272	            -- General Configurations
273	            TPD_G               => TPD_G,
274	            RST_POLARITY_G      => RST_POLARITY_G,
275	            RST_ASYNC_G         => RST_ASYNC_G,
276	            PIPE_STAGES_G       => 0,
277	            SLAVE_READY_EN_G    => true,
278	            VALID_THOLD_G       => 1,
279	            -- FIFO configurations
280	            MEMORY_TYPE_G       => "distributed",
281	            GEN_SYNC_FIFO_G     => true,
282	            FIFO_ADDR_WIDTH_G   => 4,
283	            -- AXI Stream Port Configurations
284	            SLAVE_AXI_CONFIG_G  => MASTER_AXI_CONFIG_G,
285	            MASTER_AXI_CONFIG_G => MASTER_AXI_CONFIG_G)
286	         port map (
287	            -- Slave Port
288	            sAxisClk    => mAxisClk,
289	            sAxisRst    => mAxisRst,
290	            sAxisMaster => txMaster,
291	            sAxisSlave  => txSlave,
292	            -- Master Port
293	            mAxisClk    => mAxisClk,
294	            mAxisRst    => mAxisRst,
295	            mAxisMaster => mAxisMaster,
296	            mAxisSlave  => mAxisSlave);
297	   end generate;
298	
299	end rtl;
300

