251	
252	   U_Tx : entity surf.AxiStreamGearbox
253	      generic map (
254	         -- General Configurations
255	         TPD_G               => TPD_G,
256	         RST_POLARITY_G      => RST_POLARITY_G,
257	         RST_ASYNC_G         => RST_ASYNC_G,
258	         PIPE_STAGES_G       => SLAVE_AXI_PIPE_STAGES_G,
259	         -- AXI Stream Port Configurations
260	         SLAVE_AXI_CONFIG_G  => PRBS_SSI_CONFIG_C,
261	         MASTER_AXI_CONFIG_G => SLAVE_AXI_STREAM_CONFIG_G)
262	      port map (
263	         -- Clock and reset
264	         axisClk     => sAxisClk,
265	         axisRst     => sAxisRst,
266	         -- Slave Port
267	         sAxisMaster => txAxisMaster,
268	         sAxisSlave  => txAxisSlave,
269	         -- Master Port
270	         mAxisMaster => mAxisMaster,
271	         mAxisSlave  => mAxisSlave);
272	
273	   U_bypCheck : entity surf.Synchronizer
274	      generic map (
275	         TPD_G          => TPD_G,
276	         RST_POLARITY_G => RST_POLARITY_G,
277	         RST_ASYNC_G    => RST_ASYNC_G)
278	      port map (
279	         clk     => sAxisClk,
280	         dataIn  => rAxiLite.bypCheck,
281	         dataOut => bypCheck);
282	
283	   comb : process (bypCheck, r, rxAxisMaster, sAxisRst, txAxisSlave) is
284	      variable v : RegType;
285	   begin
286	      -- Latch the current value
287	      v := r;
288	
289	      -- Reset strobe signals
290	      v.updatedResults := '0';
291	      v.errWordStrb    := '0';
292	
293	      -- AXI Stream Flow Control
294	      v.rxAxisSlave.tReady := '0';
295	      if (txAxisSlave.tReady = '1') then
296	         v.txAxisMaster.tValid := '0';
297	      end if;
298	
299	      -- Check for roll over
300	      if r.stopTime /= r.startTime then
301	         -- Increment the rate counter
302	         v.stopTime := r.stopTime + 1;
303	      end if;
304	
305	      case (r.state) is
306	         ----------------------------------------------------------------------
307	         when IDLE_S =>
308	            -- Reset the flags
309	            v.busy     := '0';
310	            v.errorDet := '0';
311	
312	            -- Check for a FIFO read and able to move data
313	            if (rxAxisMaster.tvalid = '1') and (v.txAxisMaster.tValid = '0') then
314	
315	               -- Ready to receive data
316	               v.rxAxisSlave.tReady := '1';
317	
318	               -- Move the data
319	               v.txAxisMaster := rxAxisMaster;
320	
321	               -- Check for start of frame
322	               if (ssiGetUserSof(PRBS_SSI_CONFIG_C, rxAxisMaster) = '1') and (bypCheck = '0') then
323	
324	                  -- Check for EOF
325	                  if (rxAxisMaster.tLast = '1') then
326	
327	                     -- Set the error flags
328	                     v.errorDet  := '1';
329	                     v.errLength := '1';
330	
331	                     -- Update strobe for the results
332	                     v.updatedResults := '1';
333	
334	                     -- Set the EOFE flag
335	                     ssiSetUserEofe(PRBS_SSI_CONFIG_C, v.txAxisMaster, '1');
336	
337	                  else
338	
339	                     -- Calculate the time between this packet and the previous one
340	                     if (r.stopTime = r.startTime) then
341	                        v.stopTime := r.stopTime + 1;
342	                     end if;
343	                     v.packetRate := r.stopTime - r.startTime;
344	                     v.startTime  := r.stopTime;
345	
346	                     -- Reset the error counters
347	                     v.errWordCnt      := (others => '0');
348	                     v.errMissedPacket := '0';
349	                     v.errLength       := '0';
350	                     v.errDataBus      := '0';
351	                     v.eofe            := '0';
352	
353	                     -- Check if we have missed a packet
354	                     if (rxAxisMaster.tData(EVENT_CNT_SIZE_C-1 downto 0) /= r.eventCnt) then
355	                        -- Set the error flags
356	                        v.errMissedPacket := '1';
357	                        v.errorDet        := '1';
358	                     end if;
359	
360	                     -- Align the event counter to the next packet
361	                     v.eventCnt := rxAxisMaster.tData(EVENT_CNT_SIZE_C-1 downto 0) + 1;
362	
363	                     -- Latch the SEED for the randomization
364	                     v.randomData                              := (others => '0');
365	                     v.randomData(EVENT_CNT_SIZE_C-1 downto 0) := rxAxisMaster.tData(EVENT_CNT_SIZE_C-1 downto 0);
366	
367	                     -- Set the busy flag
368	                     v.busy := '1';
369	
370	                     -- Increment the counter
371	                     v.dataCnt := r.dataCnt + 1;
372	
373	                     -- Next State
374	                     v.state := LENGTH_S;
375	
376	                  end if;
377	               else
378	                  -- Set the error flags for missing SOF and not bypCheck
379	                  v.errorDet       := not (bypCheck);
380	                  v.updatedResults := not (bypCheck);
381	               end if;
382	            end if;
383	         ----------------------------------------------------------------------
384	         when LENGTH_S =>
385	            -- Check for a FIFO read and able to move data
386	            if (rxAxisMaster.tvalid = '1') and (v.txAxisMaster.tValid = '0') then
387	
388	               -- Ready to receive data
389	               v.rxAxisSlave.tReady := '1';
390	
391	               -- Move the data
392	               v.txAxisMaster := rxAxisMaster;
393	
394	               -- Calculate the next data word
395	               v.randomData := lfsrShift(r.randomData, PRBS_TAPS_G);
396	
397	               -- Latch the packetLength value
398	               v.packetLength := rxAxisMaster.tData(31 downto 0);
399	
400	               -- Check for a data bus error
401	               for i in 4 to PRBS_SSI_CONFIG_C.TDATA_BYTES_C-1 loop
402	                  if not allBits(rxAxisMaster.tData(i*8+7 downto i*8), '0') then
403	                     v.errDataBus := '1';
404	                     v.errorDet   := '1';
405	                  end if;
406	               end loop;
407	
408	               -- Increment the counter
409	               v.dataCnt := r.dataCnt + 1;
410	
411	               -- Check for EOF
412	               if (rxAxisMaster.tLast = '1') then
413	
414	                  -- Set the error flags
415	                  v.errorDet  := '1';
416	                  v.errLength := '1';
417	
418	                  -- Set the EOFE flag
419	                  ssiSetUserEofe(PRBS_SSI_CONFIG_C, v.txAxisMaster, '1');
420	
421	                  -- Reset the counter
422	                  v.dataCnt := (others => '0');
423	
424	                  -- Update strobe for the results
425	                  v.updatedResults := '1';
426	
427	                  -- Next State
428	                  v.state := IDLE_S;
429	
430	               else
431	                  -- Next State
432	                  v.state := DATA_S;
433	               end if;
434	
435	            end if;
436	         ----------------------------------------------------------------------
437	         when DATA_S =>
438	            -- Check for a FIFO read and able to move data
439	            if (rxAxisMaster.tvalid = '1') and (v.txAxisMaster.tValid = '0') then
440	
441	               -- Ready to receive data
442	               v.rxAxisSlave.tReady := '1';
443	
444	               -- Move the data
445	               v.txAxisMaster := rxAxisMaster;
446	
447	               -- Calculate the next data word
448	               v.randomData := lfsrShift(r.randomData, PRBS_TAPS_G);
449	
450	               -- Compare the data word to calculated data word
451	               if r.randomData /= rxAxisMaster.tData(PRBS_SEED_SIZE_G-1 downto 0) then
452	                  -- Check for roll over
453	                  if r.errWordCnt /= MAX_CNT_C then
454	                     -- Error strobe
455	                     v.errWordStrb := '1';
456	                     v.errorDet    := '1';
457	                     -- Increment the word error counter
458	                     v.errWordCnt  := r.errWordCnt + 1;
459	                  end if;
460	               end if;
461	
462	               -- Check for end of frame
463	               if rxAxisMaster.tLast = '1' then
464	
465	                  -- Latch the packets eofe flag
466	                  v.eofe := ssiGetUserEofe(PRBS_SSI_CONFIG_C, rxAxisMaster);
467	
468	                  -- Check for EOFE
469	                  if v.eofe = '1' then
470	                     v.errorDet := '1';
471	                  end if;
472	
473	                  -- Check the data packet length
474	                  if r.dataCnt /= r.packetLength then
475	                     -- Wrong length detected
476	                     v.errLength := '1';
477	                     v.errorDet  := '1';
478	                  end if;
479	
480	                  -- Set the EOFE flag based on any error detected
481	                  ssiSetUserEofe(PRBS_SSI_CONFIG_C, v.txAxisMaster, v.errorDet);
482	
483	                  -- Reset the counter
484	                  v.dataCnt := (others => '0');
485	
486	                  -- Update strobe for the results
487	                  v.updatedResults := '1';
488	
489	                  -- Next State
490	                  v.state := IDLE_S;
491	
492	               -- Increment if not maximum count
493	               elsif r.dataCnt /= MAX_CNT_C then
494	                  -- Increment the counter
495	                  v.dataCnt := r.dataCnt + 1;
496	               end if;
497	
498	            end if;
499	      ----------------------------------------------------------------------
500	      end case;
501	
502	      -- Outputs
503	      rxAxisSlave     <= v.rxAxisSlave;
504	      txAxisMaster    <= r.txAxisMaster;
505	      updatedResults  <= r.updatedResults;
506	      errMissedPacket <= r.errMissedPacket;
507	      errLength       <= r.errLength;
508	      errDataBus      <= r.errDataBus;
509	      errEofe         <= r.eofe;
510	      errWordCnt      <= r.errWordCnt;
511	      packetRate      <= r.packetRate;
512	      busy            <= r.busy;
513	      packetLength    <= r.packetLength;
514	      errorDet        <= r.errorDet;
515	
516	      -- Reset
517	      if (RST_ASYNC_G = false and sAxisRst = RST_POLARITY_G) then
518	         v := REG_INIT_C;
519	      end if;
520	
521	      -- Register the variable for next clock cycle
522	      rin <= v;
523	
524	   end process comb;
525	
526	   seq : process (sAxisClk, sAxisRst) is
527	   begin
528	      if (RST_ASYNC_G) and (sAxisRst = RST_POLARITY_G) then
529	         r <= REG_INIT_C after TPD_G;
530	      elsif rising_edge(sAxisClk) then
531	         r <= rin after TPD_G;
532	      end if;
533	   end process seq;
534	
535	   SyncFifo_Inst : entity surf.SynchronizerFifo
536	      generic map (
537	         TPD_G          => TPD_G,
538	         RST_POLARITY_G => RST_POLARITY_G,
539	         RST_ASYNC_G    => RST_ASYNC_G,
540	         DATA_WIDTH_G   => 96)
541	      port map (
542	         wr_en              => r.updatedResults,
543	         wr_clk             => sAxisClk,
544	         din(31 downto 0)   => r.packetLength,
545	         din(63 downto 32)  => r.packetRate,
546	         din(95 downto 64)  => r.errWordCnt,
547	         rd_clk             => axiClk,
548	         dout(31 downto 0)  => packetLengthSync,
549	         dout(63 downto 32) => packetRateSync,
550	         dout(95 downto 64) => errWordCntSync);
551	
552	   SyncStatusVec_Inst : entity surf.SyncStatusVector
553	      generic map (
554	         TPD_G          => TPD_G,
555	         RST_POLARITY_G => RST_POLARITY_G,
556	         RST_ASYNC_G    => RST_ASYNC_G,
557	         OUT_POLARITY_G => '1',
558	         CNT_RST_EDGE_G => false,
559	         COMMON_CLK_G   => false,
560	         CNT_WIDTH_G    => STATUS_CNT_WIDTH_G,
561	         WIDTH_G        => STATUS_SIZE_C)
562	      port map (
563	         -- Input Status bit Signals (wrClk domain)
564	         statusIn(10)  => r.updatedResults,
565	         statusIn(9)   => axisCtrl(1).pause,
566	         statusIn(8)   => axisCtrl(1).overflow,
567	         statusIn(7)   => axisCtrl(0).pause,
568	         statusIn(6)   => axisCtrl(0).overflow,
569	         statusIn(5)   => '0',          -- Legacy
570	         statusIn(4)   => r.errWordStrb,
571	         statusIn(3)   => r.errDataBus,
572	         statusIn(2)   => r.eofe,
573	         statusIn(1)   => r.errLength,
574	         statusIn(0)   => r.errMissedPacket,
575	         -- Output Status bit Signals (rdClk domain)
576	         statusOut(10) => updatedResultsSync,
577	         statusOut(9)  => pause(1),
578	         statusOut(8)  => overflow(1),
579	         statusOut(7)  => pause(0),
580	         statusOut(6)  => overflow(0),
581	         statusOut(5)  => errBitStrbSync,
582	         statusOut(4)  => errWordStrbSync,
583	         statusOut(3)  => errDataBusSync,
584	         statusOut(2)  => errEofeSync,
585	         statusOut(1)  => errLengthSync,
586	         statusOut(0)  => errMissedPacketSync,
587	         -- Status Bit Counters Signals (rdClk domain)
588	         cntRstIn      => rAxiLite.cntRst,
589	         rollOverEnIn  => rAxiLite.rollOverEn,
590	         cntOut        => cntOut,
591	         -- Clocks and Reset Ports
592	         wrClk         => sAxisClk,
593	         rdClk         => axiClk);
594	
595	   frameCnt           <= muxSlVectorArray(cntOut, 10);
596	   pause1Cnt          <= muxSlVectorArray(cntOut, 9);
597	   overflow1Cnt       <= muxSlVectorArray(cntOut, 8);
598	   pause0Cnt          <= muxSlVectorArray(cntOut, 7);
599	   overflow0Cnt       <= muxSlVectorArray(cntOut, 6);
600	   -- errBitStrbCnt      <= muxSlVectorArray(cntOut, 5);
601	   errWordStrbCnt     <= muxSlVectorArray(cntOut, 4);
602	   errDataBusCnt      <= muxSlVectorArray(cntOut, 3);
603	   errEofeCnt         <= muxSlVectorArray(cntOut, 2);
604	   errLengthCnt       <= muxSlVectorArray(cntOut, 1);
605	   errMissedPacketCnt <= muxSlVectorArray(cntOut, 0);
606	
607	   -------------------------------
608	   -- Configuration Register
609	   -------------------------------
610	   combAxiLite : process (axiReadMaster, axiRst, axiWriteMaster, errDataBusCnt,
611	                          errDataBusSync, errEofeCnt, errEofeSync,
612	                          errLengthCnt, errLengthSync, errMissedPacketCnt,
613	                          errMissedPacketSync, errWordCntSync, errWordStrbCnt,
614	                          errWordStrbSync, frameCnt, overflow, overflow0Cnt,
615	                          overflow1Cnt, packetLengthSync, packetRateSync,
616	                          pause, pause0Cnt, pause1Cnt, rAxiLite) is
617	      variable v      : LocRegType;
618	      variable axilEp : AxiLiteEndpointType;
619	   begin
620	      -- Latch the current value
621	      v := rAxiLite;
622	
623	      -- Reset strobe signals
624	      v.cntRst := '0';
625	
626	      -- Determine the transaction type
627	      axiSlaveWaitTxn(axilEp, axiWriteMaster, axiReadMaster, v.axiWriteSlave, v.axiReadSlave);
628	
629	      axiSlaveRegisterR(axilEp, X"00", 0, errMissedPacketCnt);
630	      axiSlaveRegisterR(axilEp, X"04", 0, errLengthCnt);
631	      axiSlaveRegisterR(axilEp, X"08", 0, errEofeCnt);
632	      axiSlaveRegisterR(axilEp, X"0C", 0, errDataBusCnt);
633	      axiSlaveRegisterR(axilEp, X"10", 0, errWordStrbCnt);
634	      axiSlaveRegisterR(axilEp, X"14", 0, X"00000000");  -- legacy errBitStrbCnt
635	      axiSlaveRegisterR(axilEp, X"18", 0, overflow0Cnt);
636	      axiSlaveRegisterR(axilEp, X"1C", 0, pause0Cnt);
637	      axiSlaveRegisterR(axilEp, X"20", 0, overflow1Cnt);
638	      axiSlaveRegisterR(axilEp, X"24", 0, pause1Cnt);
639	      axiSlaveRegister(axilEp, X"28", 0, v.dummy);
640	      axiSlaveRegisterR(axilEp, X"70", 0, errMissedPacketSync);
641	      axiSlaveRegisterR(axilEp, X"70", 1, errLengthSync);
642	      axiSlaveRegisterR(axilEp, X"70", 2, errEofeSync);
643	      axiSlaveRegisterR(axilEp, X"70", 3, errDataBusSync);
644	      axiSlaveRegisterR(axilEp, X"70", 4, errWordStrbSync);
645	      axiSlaveRegisterR(axilEp, X"70", 5, '0');  -- legacy errBitStrbSync
646	      axiSlaveRegisterR(axilEp, X"70", 6, overflow(0));
647	      axiSlaveRegisterR(axilEp, X"70", 7, pause(0));
648	      axiSlaveRegisterR(axilEp, X"70", 8, overflow(1));
649	      axiSlaveRegisterR(axilEp, X"70", 9, pause(1));
650	      axiSlaveRegisterR(axilEp, X"74", 0, packetLengthSync);
651	      axiSlaveRegisterR(axilEp, X"78", 0, packetRateSync);
652	      axiSlaveRegisterR(axilEp, X"7C", 0, X"00000000");  -- legacy errBitCntSync
653	      axiSlaveRegisterR(axilEp, X"80", 0, errWordCntSync);
654	      axiSlaveRegisterR(axilEp, X"84", 0, frameCnt);
655	      axiSlaveRegister(axilEp, X"F0", 0, v.rollOverEn);
656	      axiSlaveRegister(axilEp, X"F4", 0, v.bypCheck);
657	      axiSlaveRegisterR(axilEp, X"F8", 0, toSlv(PRBS_SEED_SIZE_G, 32));
658	      axiWrDetect(axilEp, X"FC", v.cntRst);
659	
660	      axiSlaveDefault(axilEp, v.axiWriteSlave, v.axiReadSlave, AXI_RESP_DECERR_C);
661	
662	      -- Synchronous Reset
663	      if (RST_ASYNC_G = false and axiRst = RST_POLARITY_G) then
664	         v := LOC_REG_INIT_C;
665	      end if;
666	
667	      -- Register the variable for next clock cycle
668	      rinAxiLite <= v;
669	
670	      -- Outputs
671	      axiReadSlave  <= rAxiLite.axiReadSlave;
672	      axiWriteSlave <= rAxiLite.axiWriteSlave;
673	
674	   end process combAxiLite;
675	
676	   seqAxiLite : process (axiClk, axiRst) is
677	   begin
678	      if (RST_ASYNC_G) and (axiRst = RST_POLARITY_G) then
679	         rAxiLite <= LOC_REG_INIT_C after TPD_G;
680	      elsif rising_edge(axiClk) then
681	         rAxiLite <= rinAxiLite after TPD_G;
682	      end if;
683	   end process seqAxiLite;
684	
685	end rtl;
686

